			->setLabel( 'Index' )
;
		$pe = $fs->addElement('text', 'pe', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Price to Earnings ratio' )
;
		$tradingvolume = $fs->addElement('text', 'tradingvolume', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Trading Volume' )
;
		$institutioninterest = $fs->addElement('text', 'institutioninterest', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Percentage of shares owned by institutions' )
;
		$volatility = $fs->addElement('text', 'volatility', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'The volatility of the share' )
;
	$createduser = $fs->addElement('text', 'createduser', array() )
	->setLabel( 'Created By User' )
	->addFilter( 'trim' )
;
		$createddate = $fs->addElement('text', 'createddate', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Created Date' )
			->addFilter( 'trim' )
;
	$updateduser = $fs->addElement('text', 'updateduser', array() )
	->setLabel( 'Updated by User' )
	->addFilter( 'trim' )
;
		$dividendearningratio = $fs->addElement('text', 'dividendearningratio', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Dividends per share divided by earnings per share' )
;
		$score = $fs->addElement('text', 'score', array('size' => 11, 'maxlength' => 11) )
			->setLabel( 'Score of this filter' )
;
